/*
  # Selling Recurring Revenue™ - Modules 4-7 Complete Content

  Comprehensive lesson content for remaining modules of "Selling Recurring Revenue™"

  Module 4: Demonstrating Ongoing Value (8 lessons)
  Module 5: Pricing Recurring Services (8 lessons)
  Module 6: Selling CRM Subscriptions (8 lessons)
  Module 7: Building Your MRR Portfolio (8 lessons)
*/

DO $$
DECLARE
  v_course_id uuid;
  v_module_4_id uuid;
  v_module_5_id uuid;
  v_module_6_id uuid;
  v_module_7_id uuid;
BEGIN
  -- Get course ID
  SELECT id INTO v_course_id FROM courses WHERE slug = 'selling-recurring-revenue-partner';

  IF v_course_id IS NULL THEN
    RAISE EXCEPTION 'Course not found: selling-recurring-revenue-partner';
  END IF;

  -- Get Module IDs
  SELECT id INTO v_module_4_id FROM course_modules WHERE course_id = v_course_id AND module_index = 4;
  SELECT id INTO v_module_5_id FROM course_modules WHERE course_id = v_course_id AND module_index = 5;
  SELECT id INTO v_module_6_id FROM course_modules WHERE course_id = v_course_id AND module_index = 6;
  SELECT id INTO v_module_7_id FROM course_modules WHERE course_id = v_course_id AND module_index = 7;

  -- MODULE 4: Demonstrating Ongoing Value

  -- MODULE 5: Pricing Recurring Services

  -- MODULE 6: Selling CRM Subscriptions (abbreviated for space)

  -- MODULE 7: Building Your MRR Portfolio
  ON CONFLICT DO NOTHING;

END $$;
